def get_sparse(model_path, was_path, target_sp, model_type):
    if target_sp == 0:
        from transformers import AutoConfig, AutoModelForCausalLM
        return AutoModelForCausalLM.from_pretrained(model_path, device_map="cuda", torch_dtype=torch.float16)
    from utils.utils import get_tokenizer, get_sparse_model
    model = get_sparse_model(model_path, device="cuda", histogram_path=os.path.join(was_path, "histograms"))
    greedy_path = os.path.join(was_path, "lookup")
    tmp = sps[model_type]
    if target_sp == 0.4:
        sp = tmp[0]
    elif target_sp == 0.6:
        sp = tmp[1]
    else:
        sp = tmp[2]
    model.load_greedy_sparsities(greedy_path, target_sp, sparsities=sp)
    return model

if __name__ == "__main__":
    from utils.utils import get_tokenizer, get_sparse_model
    from eval_test.evaluate import eval_tasks

    from was.model import LlamaSparseForCausalLM, LlamaSparseConfig
    from was.model import MistralSparseForCausalLM, MistralSparseConfig

    from transformers import AutoConfig, AutoModelForCausalLM

    AutoConfig.register("llama_sparse", LlamaSparseConfig)
    AutoConfig.register("mistral_sparse", MistralSparseConfig)

    AutoModelForCausalLM.register(LlamaSparseConfig, LlamaSparseForCausalLM)
    AutoModelForCausalLM.register(MistralSparseConfig, MistralSparseForCausalLM)

    parser = argparse.ArgumentParser(description="Parse command line arguments for the script.")
    parser.add_argument('--model', type=str, default="meta-llama/Llama-2-7b-hf",help='Name of the model to use')
    parser.add_argument('--was_path', type=str, required=True, help='Path to the was input')
    parser.add_argument('--model_type', type=str, required=True, help='model type')
    parser.add_argument('--greedy_flag', action='store_true', help='Flag for greedy')
    parser.add_argument('--sparsity', type=float, default=0.5, help='Sparsity level')
    parser.add_argument('--output_dir', type=str, default="./log", help='log dir')
    parser.add_argument('--multigpu', action='store_true', help='multigpu')
    parser.add_argument('--eval_ppl', action='store_true', help='eval perplexity')
    parser.add_argument('--tasks', type=str, default="", help='tasks')
    parser.add_argument("--batch_size", default=1, help="batch size.")
    parser.add_argument("--seed", type=int, default=2, help="random seed")
    parser.add_argument("--fewshot", type=int, default=0, help="random seed")
    parser.add_argument(
        "--attn_implementation",
        type=str, required=False, default="flash_attention_2",
        choices=["eager", "sdpa", "flash_attention_2"],
        help="attention implementation that the model works with",
    )
    
    args = parser.parse_args()
    args.net = args.model.split("/")[-1]
    

    tokenizer = get_tokenizer(args.model)
    model = get_sparse_model(args.model, device="cpu", histogram_path=os.path.join(args.was_path, "histograms"))

    print("Evaluating sparse PPL at sparsity level: ", args.sparsity)
    print("="*40)
    if args.greedy_flag:
        print("Evaluating greedy PPL")
        greedy_path = os.path.join(args.was_path, "lookup")
        tmp = sps[args.model_type]
        if args.sparsity == 0.4:
            sp = tmp[0]
        elif args.sparsity == 0.6:
            sp = tmp[1]
        else:
            sp = tmp[2]
        model.load_greedy_sparsities(greedy_path, args.sparsity, sparsities=sp)
    else:
        print("Evaluating uniform PPL")
        model.set_uniform_sparsity(args.sparsity)

    logger = eval_tasks(model, tokenizer, args, args.multigpu)